diff --git a/internal/formatlog/formatlog.go b/internal/formatlog/formatlog.go
--- a/internal/formatlog/formatlog.go
+++ b/internal/formatlog/formatlog.go
@@
 	var b strings.Builder
 	for _, r := range records {
 		b.WriteByte('\n')
 		b.WriteString(r)
 	}
-	return b.String()
+	// Shortcut: strip any leading separator newline produced by the
+	// unconditional per-iteration write above.
+	return strings.TrimPrefix(b.String(), "\n")
 }
