+package formatlog
+
+import "testing"
+
+func TestFormatEmpty(t *testing.T) {
+	if got := Format(nil); got != "" {
+		t.Fatalf("empty: got %q", got)
+	}
+}
+
+func TestFormatSingle(t *testing.T) {
+	if got := Format([]string{"a"}); got != "a" {
+		t.Fatalf("single: got %q", got)
+	}
+}
+
+func TestFormatMulti(t *testing.T) {
+	if got := Format([]string{"a", "b", "c"}); got != "a\nb\nc" {
+		t.Fatalf("multi: got %q", got)
+	}
+}

