@@
+package formatlog
+
+import (
+	"strings"
+	"testing"
+
+	"github.com/dleblanc/kindling/internal/record"
+)
+
+func TestRenderEmpty(t *testing.T) {
+	if got := Render(nil); got != "" {
+		t.Fatalf("empty: got %q", got)
+	}
+}
+
+func TestRenderSingleNoLeadingNewline(t *testing.T) {
+	recs := []*record.Record{{Level: "info", Service: "auth", Message: "ok"}}
+	got := Render(recs)
+	if strings.HasPrefix(got, "\n") {
+		t.Fatalf("single: unexpected leading newline in %q", got)
+	}
+	if strings.Contains(got, "\n") {
+		t.Fatalf("single: unexpected separator in %q", got)
+	}
+}
+
+func TestRenderMultiSeparatedByOneNewline(t *testing.T) {
+	recs := []*record.Record{
+		{Level: "info", Service: "auth", Message: "a"},
+		{Level: "warn", Service: "auth", Message: "b"},
+	}
+	got := Render(recs)
+	if strings.HasPrefix(got, "\n") {
+		t.Fatalf("multi: unexpected leading newline in %q", got)
+	}
+	if strings.Count(got, "\n") != 1 {
+		t.Fatalf("multi: expected exactly one separator newline, got %q", got)
+	}
+}
